  );
}


/* ══════════════════════════════════════════════════════════════
   ACTION PLAN
══════════════════════════════════════════════════════════════ */
function ActionPlan({ profiles, meta, summary }) {
  const [status,   setStatus]   = useState("idle"); // idle | loading | done | error
  const [markdown, setMarkdown] = useState("");
  const [errorMsg, setErrorMsg] = useState("");

  const generate = async () => {
    setStatus("loading");
    setMarkdown("");
    setErrorMsg("");
    try {
      const res = await fetch(`${API}/ai/action-plan`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ profiles, meta, summary }),
      });
      if (!res.ok) {
        const d = await res.json().catch(() => ({}));
        throw new Error(d.detail || "Request failed");
      }
      const reader = res.body.getReader();
      const dec    = new TextDecoder();
      let   full   = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        full += dec.decode(value, { stream: true });
        setMarkdown(full);
      }
      setStatus("done");
    } catch (e) {
      setErrorMsg(e.message);
      setStatus("error");
    }
  };

  // Parse markdown table into { headers, rows }
  const parseTable = (md) => {
    const lines = md.trim().split("\n").filter(l => l.trim().startsWith("|"));
    if (lines.length < 2) return null;
    const parseRow = (line) =>
      line.split("|").slice(1, -1).map(c => c.trim());
    const headers = parseRow(lines[0]);
    const rows    = lines.slice(2).map(parseRow); // skip separator line
    return { headers, rows };
  };

  const table = status === "done" ? parseTable(markdown) : null;

  return (
    <div className="action-plan-section">
      <div className="action-plan-header">
        <p className="action-plan-title">AI Action Plan</p>
        <button
          className="action-plan-btn"
          onClick={generate}
          disabled={status === "loading"}
        >
          {status === "loading" ? (
            <><span className="ap-spinner" /> Generating…</>
          ) : status === "done" ? (
            <>↻ Regenerate</>
          ) : (
            <>✨ Generate Action Plan</>
          )}
        </button>
      </div>

      {status === "loading" && !markdown && (
        <div className="action-plan-loading">
          <span className="ap-spinner" />
          Asking AI for recommendations…
        </div>
      )}

      {status === "error" && (
        <div className="action-plan-error">⚠️ {errorMsg}</div>
      )}

      {markdown && (
        table ? (
          <div className="action-plan-table-wrap">
            <table>
              <thead>
                <tr>{table.headers.map((h, i) => <th key={i}>{h}</th>)}</tr>
              </thead>
              <tbody>
                {table.rows.map((row, i) => (
                  <tr key={i}>{row.map((cell, j) => <td key={j}>{cell}</td>)}</tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <pre className="action-plan-raw">{markdown}</pre>
        )
      )}
    </div>
  );
}


/* ══════════════════════════════════════════════════════════════
   AI CHAT
══════════════════════════════════════════════════════════════ */
const SUGGESTIONS = [
  "Which segment should I focus on first?",
  "Who are my most valuable customers?",
  "What are my top selling products?",
  "Which segment is most at risk of churning?",
  "What's my best sales day of the week?",
  "What % of revenue do Champions represent?",
];

function AiChat({ context }) {
  const [messages,  setMessages]  = useState([]);  // [{role, content}]
  const [input,     setInput]     = useState("");
  const [streaming, setStreaming] = useState(false);
  const bottomRef  = useRef(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth", block: "nearest" });
  }, [messages]);

  const send = useCallback(async (text) => {
    const msg = (text || input).trim();
    if (!msg || streaming) return;
    setInput("");

    const userMsg = { role: "user", content: msg };
    setMessages(prev => [...prev, userMsg]);
    setStreaming(true);

    // Placeholder AI message that we'll stream into
    const aiPlaceholder = { role: "assistant", content: "" };
    setMessages(prev => [...prev, aiPlaceholder]);

    try {
      const res = await fetch(`${API}/ai/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: msg,
          history: messages, // send existing history (before new user msg)
          context,
        }),
      });
      if (!res.ok) {
        const d = await res.json().catch(() => ({}));
        throw new Error(d.detail || "Request failed");
      }
      const reader = res.body.getReader();
      const dec    = new TextDecoder();
      let   full   = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        full += dec.decode(value, { stream: true });
        setMessages(prev => [
          ...prev.slice(0, -1),
          { role: "assistant", content: full },
        ]);
      }
    } catch (e) {
      setMessages(prev => [
        ...prev.slice(0, -1),
        { role: "assistant", content: `⚠️ Error: ${e.message}` },
      ]);
    } finally {
      setStreaming(false);
    }
  }, [input, streaming, messages, context]);

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      send();
    }
  };

  return (
    <div className="ai-chat-section">
      {/* Header */}
      <div className="ai-chat-header">
        <div className="ai-chat-title">
          🧠 Ask Your Data
          <span className="ai-chat-badge">AI</span>
        </div>
        {messages.length > 0 && (
          <button className="ai-chat-clear" onClick={() => setMessages([])}>
            Clear chat
          </button>
        )}
      </div>

      {/* Suggestions (only when empty) */}
      {messages.length === 0 && (
        <div className="ai-chat-suggestions">
          {SUGGESTIONS.map((s, i) => (
            <button key={i} className="suggestion-chip" onClick={() => send(s)}>
              {s}
            </button>
          ))}
        </div>
      )}

      {/* Message list */}
      <div className="ai-chat-messages">
        {messages.length === 0 ? (
          <div className="ai-chat-empty">
            <span className="ai-chat-empty-icon">💬</span>
            <p className="ai-chat-empty-text">Ask anything about your segments</p>
            <p className="ai-chat-empty-sub">Try one of the suggestions above</p>
          </div>
        ) : (
          messages.map((m, i) => (
            <div key={i} className={`chat-msg chat-msg-${m.role === "user" ? "user" : "ai"}`}>
              <div className="chat-msg-avatar">
                {m.role === "user" ? "👤" : "🧠"}
              </div>
              <div className="chat-msg-bubble">
                {m.role === "assistant" && m.content === "" ? (
                  <div className="chat-typing">
                    <span className="chat-typing-dot" />
                    <span className="chat-typing-dot" />
                    <span className="chat-typing-dot" />
                  </div>
                ) : (
                  m.content
                )}
              </div>
            </div>
          ))
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div className="ai-chat-input-row">
        <textarea
          ref={textareaRef}
          className="ai-chat-input"
          placeholder="Ask a question about your customer data…"
          value={input}
          rows={1}
          onChange={e => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          disabled={streaming}
        />
        <button
          className="ai-chat-send"
          onClick={() => send()}
          disabled={!input.trim() || streaming}
          title="Send"
        >
          ↑
        </button>
      </div>
    </div>
  );
}
